  'server rack': '#A3E851',
  'barcode scanner': '#5DC987',
  'gaming console': '#A3E851',
  'smartwatch / wearable': '#05042E',
  'thin client': '#5DC987',
  'pos terminal': '#469BC0',
  'iot device': '#A3E851',
  'cables & accessories': '#E0DFE1'
};
function getIcon(name) {
  if (!name) return '📦';
  return iconMap[name.toLowerCase()] || '📦';
}
function getColor(name) {
  if (!name) return '#469BC0';
  return colorMap[name.toLowerCase()] || '#469BC0';
}
function render(model) {
  var data = model && model.assets ? model.assets : [];
  var grid = document.getElementById('grid');
  if (!data.length) {
    grid.innerHTML = '<div class="empty">No asset data found</div>';
    return;
  }
  grid.innerHTML = data.map(function (r) {
    var bg = getColor(r.item_type_name);
    var textColor = bg === '#A3E851' || bg === '#E0DFE1' ? '#05042E' : '#fff';
    return '<div class="card">' + '<div class="card-top">' + '<div class="icon" style="background:' + bg + ';color:' + textColor + '">' + getIcon(r.item_type_name) + '</div>' + '<div class="type-name">' + (r.item_type_name || '—') + '</div>' + '</div>' + '<div class="total" style="color:' + bg + '">' + (r.total || 0) + '</div>' + '<div class="stats">' + '<div class="stat"><span class="stat-label">Month</span><span class="stat-value">' + (r.this_month || 0) + '</span></div>' + '<div class="stat"><span class="stat-label">Year</span><span class="stat-value">' + (r.this_year || 0) + '</span></div>' + '</div>' + '</div>';
  }).join('');
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function () {
  render(appsmith.model);
});

